#ifndef GEMM_N4096_K4096_KERNEL_H_
#define GEMM_N4096_K4096_KERNEL_H_

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <torch/extension.h>

// Kernel launch wrapper for CUDA implementation
// A: [M, 4096] half
// B: [4096, 4096] half (multiplied as B^T)
// C: [M, 4096] half
void gemm_n4096_k4096_launch(const __half* A, const __half* B, __half* C, int M, cudaStream_t stream);

// PyTorch binding entry point
torch::Tensor run(torch::Tensor A, torch::Tensor B);

#endif // GEMM_N4096_K4096_KERNEL_H_

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <mma.h>
#include <stdint.h>
#include "kernel.h"

using namespace nvcuda;

#ifndef CUDA_CHECK
#define CUDA_CHECK(err) \
  do { \
    cudaError_t err__ = (err); \
    if (err__ != cudaSuccess) { \
      printf("CUDA error %s at %s:%d\n", cudaGetErrorString(err__), __FILE__, __LINE__); \
    } \
  } while (0)
#endif

// GEMM C[M,4096] = A[M,4096] * B^T where B is [4096,4096], half precision inputs/outputs with FP32 accumulation.
// Tile sizes tuned for A800 (SM80): BM=128, BN=128, BK=16. WMMA Tensor Cores used with shared memory staging.
//
// Shared memory layout per block (dynamic):
// - smemA: half [BM * BK]  = 128 x 16
// - smemB: half [BK * BN]  = 16 x 128 (stored as column-major tile for WMMA B operand)
// - smemC: float [BM * BN] = 128 x 128 (accumulator written here; later converted to half and written to global)
template<int BM, int BN, int BK>
__global__ void __launch_bounds__(256, 2)
gemm_n4096_k4096_kernel_fp16_tc(const __half* __restrict__ A,
                                 const __half* __restrict__ B,
                                 __half* __restrict__ C,
                                 int M) {
  constexpr int N = 4096;
  constexpr int K = 4096;

  extern __shared__ uint8_t smem_raw[];
  __half* smemA = reinterpret_cast<__half*>(smem_raw);
  __half* smemB = smemA + (BM * BK);
  float*  smemC = reinterpret_cast<float*>(smemB + (BK * BN));

  const int tid = threadIdx.x;
  const int block_m = blockIdx.y * BM;
  const int block_n = blockIdx.x * BN;

  // Warp mapping: 8 warps per block (256 threads)
  // - along M: BM / 32 = 4
  // - along N: BN / 64 = 2
  const int warp_id = tid >> 5;     // 0..7
  const int lane_id = tid & 31;
  const int WARPS_M = BM / 32;      // 4
  const int WARPS_N = BN / 64;      // 2
  const int warp_m = warp_id % WARPS_M; // 0..3
  const int warp_n = warp_id / WARPS_M; // 0..1

  // Accumulator fragments for each warp: 2 (M) x 4 (N) = 8 tiles (each 16x16)
  wmma::fragment<wmma::accumulator, 16, 16, 16, float> c_frag[2][4];
#pragma unroll
  for (int i = 0; i < 2; ++i) {
#pragma unroll
    for (int j = 0; j < 4; ++j) {
      wmma::fill_fragment(c_frag[i][j], 0.0f);
    }
  }

  // Loop over K dimension in steps of BK=16
  for (int k0 = 0; k0 < K; k0 += BK) {
    // Cooperative load of A tile: [BM x BK] = [128 x 16], row-major in shared (ld = BK)
    {
      int row = tid % BM;         // 0..127
      int seg = tid / BM;         // 0..1 -> two segments of 8 elements (int4) per row
      int a_g_row = block_m + row;
      int a_g_col = k0 + seg * 8;

      int s_off = row * BK + seg * 8;
      if (a_g_row < M) {
        const int4* src = reinterpret_cast<const int4*>(A + a_g_row * K + a_g_col);
        int4 val = *src;
        int4* dst = reinterpret_cast<int4*>(smemA + s_off);
        *dst = val;
      } else {
        // Out-of-bounds rows: zero fill to avoid invalid reads
        int4 zero; zero.x = 0; zero.y = 0; zero.z = 0; zero.w = 0;
        int4* dst = reinterpret_cast<int4*>(smemA + s_off);
        *dst = zero;
      }
    }

    // Cooperative load of B tile: [BK x BN] = [16 x 128], store as column-major in shared with ld = BK
    {
      int col = tid % BN;         // 0..127 (N axis within block)
      int seg = tid / BN;         // 0..1 -> two segments of 8 elements along K
      int b_g_row = block_n + col;    // B row index in [N]
      int b_g_col = k0 + seg * 8;     // B col index in [K]

      const int4* src = reinterpret_cast<const int4*>(B + b_g_row * K + b_g_col);
      int4 val = *src;

      int s_off = col * BK + seg * 8; // col-major storage: offset = j*ld + i
      int4* dst = reinterpret_cast<int4*>(smemB + s_off);
      *dst = val;
    }

    __syncthreads();

    // Load A and B fragments from shared memory and accumulate
    wmma::fragment<wmma::matrix_a, 16, 16, 16, __half, wmma::row_major> a_frag[2];
    wmma::fragment<wmma::matrix_b, 16, 16, 16, __half, wmma::col_major> b_frag[4];

#pragma unroll
    for (int i = 0; i < 2; ++i) {
      const __half* a_tile_ptr = smemA + (warp_m * 32 + i * 16) * BK;
      wmma::load_matrix_sync(a_frag[i], a_tile_ptr, BK);
    }

#pragma unroll
    for (int j = 0; j < 4; ++j) {
      const __half* b_tile_ptr = smemB + (warp_n * 64 + j * 16) * BK;
      wmma::load_matrix_sync(b_frag[j], b_tile_ptr, BK);
    }

#pragma unroll
    for (int i = 0; i < 2; ++i) {
#pragma unroll
      for (int j = 0; j < 4; ++j) {
        wmma::mma_sync(c_frag[i][j], a_frag[i], b_frag[j], c_frag[i][j]);
      }
    }

    __syncthreads();
  }

  // Store accumulators to shared memory C tile (float), row-major with ld = BN
#pragma unroll
  for (int i = 0; i < 2; ++i) {
#pragma unroll
    for (int j = 0; j < 4; ++j) {
      int row_off = warp_m * 32 + i * 16;
      int col_off = warp_n * 64 + j * 16;
      float* c_tile_ptr = smemC + row_off * BN + col_off;
      wmma::store_matrix_sync(c_tile_ptr, c_frag[i][j], BN, wmma::mem_row_major);
    }
  }

  __syncthreads();

  // Convert C tile from float (smemC) to half and store to global C with bounds check on M
  // Each thread handles 8 elements (segment) per iteration; total segments = (BM * BN) / 8
  const int segments_per_row = BN / 8;   // 128 / 8 = 16
  const int total_segments = (BM * BN) / 8; // 16384 / 8 = 2048

  for (int seg_idx = tid; seg_idx < total_segments; seg_idx += blockDim.x) {
    int row = seg_idx / segments_per_row;                 // 0..127
    int seg_in_row = seg_idx % segments_per_row;          // 0..15
    int col_start = seg_in_row * 8;

    int g_row = block_m + row;
    if (g_row < M) {
      const float* srcf = smemC + row * BN + col_start;
      __half* dsth = C + g_row * N + block_n + col_start;

      // Convert 8 floats to 8 half
      float f0 = srcf[0];
      float f1 = srcf[1];
      float f2 = srcf[2];
      float f3 = srcf[3];
      float f4 = srcf[4];
      float f5 = srcf[5];
      float f6 = srcf[6];
      float f7 = srcf[7];

      dsth[0] = __float2half_rn(f0);
      dsth[1] = __float2half_rn(f1);
      dsth[2] = __float2half_rn(f2);
      dsth[3] = __float2half_rn(f3);
      dsth[4] = __float2half_rn(f4);
      dsth[5] = __float2half_rn(f5);
      dsth[6] = __float2half_rn(f6);
      dsth[7] = __float2half_rn(f7);
    }
  }
}

// Wrapper to launch the templated kernel with tuned parameters and dynamic shared memory configuration
void gemm_n4096_k4096_launch(const __half* A, const __half* B, __half* C, int M, cudaStream_t stream) {
  constexpr int N = 4096;
  constexpr int K = 4096;
  constexpr int BM = 128;
  constexpr int BN = 128;
  constexpr int BK = 16;

  if (M <= 0) return;

  dim3 block(256, 1, 1);                             // 8 warps
  dim3 grid(N / BN, (M + BM - 1) / BM, 1);          // x: 4096/128=32, y: ceil(M/128)

  size_t smem_bytes =
      (BM * BK) * sizeof(__half) +      // A tile
      (BK * BN) * sizeof(__half) +      // B tile
      (BM * BN) * sizeof(float);        // C tile (accumulator)

  // Increase dynamic shared memory limit for this kernel (A800 supports large SMEM)
  CUDA_CHECK(cudaFuncSetAttribute(
      gemm_n4096_k4096_kernel_fp16_tc<BM, BN, BK>,
      cudaFuncAttributeMaxDynamicSharedMemorySize,
      (int)smem_bytes));

  gemm_n4096_k4096_kernel_fp16_tc<BM, BN, BK>
      <<<grid, block, smem_bytes, stream>>>(A, B, C, M);

  CUDA_CHECK(cudaGetLastError());
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>
#include <vector>
#include <stdexcept>
#include <sstream>
#include "kernel.h"

static void check_inputs(const torch::Tensor& A, const torch::Tensor& B) {
  if (A.dim() != 2) {
    throw std::invalid_argument("A must be 2D [M, 4096]");
  }
  if (B.dim() != 2) {
    throw std::invalid_argument("B must be 2D [4096, 4096]");
  }
  if (A.size(1) != 4096) {
    std::ostringstream oss;
    oss << "A.size(1) must be 4096, got " << A.size(1);
    throw std::invalid_argument(oss.str());
  }
  if (B.size(0) != 4096 || B.size(1) != 4096) {
    std::ostringstream oss;
    oss << "B must be [4096, 4096], got [" << B.size(0) << ", " << B.size(1) << "]";
    throw std::invalid_argument(oss.str());
  }
  if (A.dtype() != torch::kFloat16) {
    throw std::invalid_argument("A must be torch.float16");
  }
  if (B.dtype() != torch::kFloat16) {
    throw std::invalid_argument("B must be torch.float16");
  }
}

torch::Tensor run(torch::Tensor A_in, torch::Tensor B_in) {
  try {
    check_inputs(A_in, B_in);

    // Ensure contiguous tensors
    torch::Tensor A_c = A_in.contiguous();
    torch::Tensor B_c = B_in.contiguous();

    const bool A_was_cuda = A_c.device().is_cuda();
    const bool B_was_cuda = B_c.device().is_cuda();

    // Move to CUDA if on CPU
    torch::Tensor A = A_c;
    torch::Tensor B = B_c;
    int device_index = 0;

    if (!A_was_cuda || !B_was_cuda) {
      // If one is CPU and other is CUDA or both CPU, move both to same CUDA device 0
      A = A_c.to(torch::kCUDA, /*non_blocking=*/false);
      B = B_c.to(torch::kCUDA, /*non_blocking=*/false);
      device_index = A.get_device();
    } else {
      // Both on CUDA; ensure same device
      int devA = A_c.get_device();
      int devB = B_c.get_device();
      if (devA != devB) {
        std::ostringstream oss;
        oss << "A and B must be on the same CUDA device. Got A on " << devA << ", B on " << devB;
        throw std::invalid_argument(oss.str());
      }
      device_index = devA;
    }

    // Dimensions
    const int64_t M64 = A.size(0);
    if (M64 < 0) {
      throw std::invalid_argument("Invalid M dimension for A");
    }
    const int M = static_cast<int>(M64);

    // Allocate output tensor C on CUDA
    auto options = torch::TensorOptions().dtype(torch::kFloat16).device(torch::kCUDA, device_index);
    torch::Tensor C = torch::empty({M64, 4096}, options);

    // Get raw pointers
    const __half* A_ptr = reinterpret_cast<const __half*>(A.data_ptr<at::Half>());
    const __half* B_ptr = reinterpret_cast<const __half*>(B.data_ptr<at::Half>());
    __half* C_ptr = reinterpret_cast<__half*>(C.data_ptr<at::Half>());

    // Set CUDA device and stream
    at::cuda::CUDAGuard device_guard(device_index);
    cudaStream_t stream = at::cuda::getCurrentCUDAStream(device_index);

    // Launch kernel
    gemm_n4096_k4096_launch(A_ptr, B_ptr, C_ptr, M, stream);

    // Synchronize and check for errors
    cudaError_t err_sync = cudaStreamSynchronize(stream);
    if (err_sync != cudaSuccess) {
      std::ostringstream oss;
      oss << "CUDA Stream Synchronize failed: " << cudaGetErrorString(err_sync);
      throw std::runtime_error(oss.str());
    }

    // If original inputs were CPU, move result back to CPU
    if (!A_was_cuda || !B_was_cuda) {
      return C.to(torch::kCPU);
    } else {
      return C;
    }
  } catch (const c10::Error& e) {
    std::ostringstream oss;
    oss << "Torch/c10 error in run: " << e.msg();
    throw std::runtime_error(oss.str());
  } catch (const std::exception& e) {
    std::ostringstream oss;
    oss << "Exception in run: " << e.what();
    throw std::runtime_error(oss.str());
  } catch (...) {
    throw std::runtime_error("Unknown error in run");
  }
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "Kernel execution function");
}
